 1→import express from 'express';
 2→import { registerSkillsRoutes } from './routes/skills.js';
 3→
 4→export function createApp() {
 5→  const app = express();
 6→  app.set('trust proxy', true);
 7→  app.use(express.json());
 8→
 9→  app.get('/health', (req, res) => {
10→    res.json({ status: 'ok' });
11→  });
12→
13→  registerSkillsRoutes(app);
14→
15→  return app;
