 1→const ERC_INTERFACES = {
 2→  'ERC-20': ['transfer', 'approve', 'transferFrom', 'balanceOf', 'totalSupply', 'allowance'],
 3→  'ERC-721': ['ownerOf', 'safeTransferFrom', 'getApproved', 'setApprovalForAll'],
 4→  'ERC-1155': ['balanceOfBatch', 'safeBatchTransferFrom', 'safeTransferFrom'],
 5→  'ERC-4626': ['deposit', 'withdraw', 'redeem', 'convertToAssets', 'convertToShares', 'totalAssets'],
 6→};
 7→
 8→export function detectERCPatterns(abi) {
 9→  const functionNames = new Set(
10→    abi.filter((item) => item.type === 'function').map((item) => item.name)
11→  );
12→
13→  return Object.entries(ERC_INTERFACES)
14→    .filter(([, signatures]) => signatures.every((sig) => functionNames.has(sig)))
15→    .map(([standard]) => standard);
16→}
